content:
/* ========================================
   Butterfly Theme - Visual Reset
   半透明白 + 现代字体 + 去除所有深蓝色调
   ======================================== */

/* ========================================
   粒子背景容器
   ======================================== */
#particle-bg {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  z-index: -1;
  pointer-events: none;
}

/* ========================================
   头部动态渐变背景
   ======================================== */
#page-header {
  position: relative;
  overflow: hidden;
}

#page-header::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  min-height: 30vh;
  background: linear-gradient(60deg, rgba(184, 166, 217, 0.25), rgba(200, 180, 220, 0.15), rgba(220, 200, 210, 0.25));
  z-index: 0;
  pointer-events: none;
}

/* 全局背景重置：半透明白，去除所有深蓝色调 */
body, .main-inner, .content-wrap, #content, .post-block, .sidebar-inner {
    background: rgba(255, 255, 255, 0.88) !important;
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
}

/* 现代字体优化：避开过于尖锐的日式字体，使用平滑、稳重的高级感字体库 */
body, .post-body, h1, h2, h3, h4 {
    font-family: -apple-system, "PingFang SC", "Lantinghei SC", "Microsoft YaHei", "Helvetica Neue", Helvetica, Arial, sans-serif !important;
    color: #2c3e50 !important;
    line-height: 1.8;
}

/* 移除顽固蓝色元素（链接与主题色） */
a, a:hover, .post-title-link, .menu-item-active a {
    color: #555 !important;
    border-bottom: none !important;
}

/* ========================================
   核弹级：覆盖 CSS 变量，从根源消灭蓝色
   ======================================== */

:root {
    --card-bg: rgba(255, 255, 255, 0.88) !important;
    --btn-bg: rgba(255, 255, 255, 0.6) !important;
    --btn-color: #555 !important;
    --btn-hover-color: rgba(255, 255, 255, 0.8) !important;
    --card-box-shadow: none !important;
    --card-hover-box-shadow: none !important;
    --sidebar-bg: rgba(255, 255, 255, 0.5) !important;
    --global-bg: transparent !important;
    --text-highlight-color: #2c3e50 !important;
    --theme-color: #555 !important;
    --light-blue: #555 !important;
}

[data-theme="dark"] {
    --card-bg: rgba(30, 30, 30, 0.85) !important;
    --btn-bg: rgba(30, 30, 30, 0.6) !important;
    --btn-color: #aaa !important;
    --btn-hover-color: rgba(30, 30, 30, 0.8) !important;
    --sidebar-bg: rgba(30, 30, 30, 0.5) !important;
    --text-highlight-color: #ddd !important;
}

/* ========================================
   卡片与按钮统一
   ======================================== */

.cardHover,
.card-widget,
.recent-post-item {
    background: rgba(255, 255, 255, 0.88) !important;
    backdrop-filter: blur(10px) !important;
    -webkit-backdrop-filter: blur(10px) !important;
    box-shadow: none !important;
    border: 1px solid rgba(255, 255, 255, 0.6) !important;
    border-radius: 12px;
}

.cardHover:hover {
    box-shadow: none !important;
}

[data-theme="dark"] .cardHover,
[data-theme="dark"] .card-widget,
[data-theme="dark"] .recent-post-item {
    background: rgba(30, 30, 30, 0.85) !important;
    border: 1px solid rgba(255, 255, 255, 0.08) !important;
}

/* ========================================
   首页全屏头图 - 浅白半透明磨砂玻璃
   ======================================== */

#page-header.full_page {
    background: rgba(255, 255, 255, 0.4) !important;
    backdrop-filter: blur(15px) !important;
    -webkit-backdrop-filter: blur(15px) !important;
}

#page-header.full_page:before {
    background: none !important;
    background-image: none !important;
}

#page-header.full_page #site-title,
#page-header.full_page #site-subtitle {
    color: #333 !important;
    text-shadow: none !important;
}

[data-theme="dark"] #page-header.full_page {
    background: rgba(30, 30, 30, 0.4) !important;
}

[data-theme="dark"] #page-header.full_page #site-title,
[data-theme="dark"] #page-header.full_page #site-subtitle {
    color: #ddd !important;
}

/* ========================================
   导航栏 - 浅白半透明磨砂玻璃
   ======================================== */

#nav {
    background: rgba(255, 255, 255, 0.7) !important;
    backdrop-filter: blur(10px) !important;
    -webkit-backdrop-filter: blur(10px) !important;
    border-bottom: 1px solid rgba(255, 255, 255, 0.3) !important;
    transition: all 0.4s ease !important;
}

#nav.nav-fixed,
#nav.show {
    background: rgba(255, 255, 255, 0.7) !important;
    backdrop-filter: blur(10px) !important;
    -webkit-backdrop-filter: blur(10px) !important;
    box-shadow: 0 2px 20px rgba(0, 0, 0, 0.06) !important;
    border-bottom: 1px solid rgba(255, 255, 255, 0.4) !important;
}

[data-theme="dark"] #nav {
    background: rgba(30, 30, 30, 0.7) !important;
    border-bottom: 1px solid rgba(255, 255, 255, 0.08) !important;
}

[data-theme="dark"] #nav.nav-fixed,
[data-theme="dark"] #nav.show {
    background: rgba(30, 30, 30, 0.7) !important;
    border-bottom: 1px solid rgba(255, 255, 255, 0.12) !important;
}

/* ========================================
   底栏 - 浅白半透明磨砂玻璃
   ======================================== */

#footer {
    background: rgba(255, 255, 255, 0.4) !important;
    backdrop-filter: blur(15px) !important;
    -webkit-backdrop-filter: blur(15px) !important;
    border-top: 1px solid rgba(255, 255, 255, 0.3) !important;
    color: #333 !important;
    text-shadow: none !important;
}

#footer:before {
    background: none !important;
    background-image: none !important;
}

#footer,
#footer a,
#footer .copyright,
#footer .framework-info,
#footer .footer_custom_text,
#footer .footer-flex-title,
#footer .footer-flex-item {
    color: #333 !important;
    text-shadow: none !important;
}

[data-theme="dark"] #footer {
    background: rgba(30, 30, 30, 0.4) !important;
    border-top: 1px solid rgba(255, 255, 255, 0.08) !important;
}

[data-theme="dark"] #footer,
[data-theme="dark"] #footer a,
[data-theme="dark"] #footer .copyright,
[data-theme="dark"] #footer .framework-info,
[data-theme="dark"] #footer .footer_custom_text,
[data-theme="dark"] #footer .footer-flex-title,
[data-theme="dark"] #footer .footer-flex-item {
    color: #aaa !important;
}

/* ========================================
   全景壁纸锁定
   ======================================== */

body {
    background-image: url(/img/background.jpg) !important;
    background-attachment: fixed !important;
    background-size: cover !important;
    background-position: center !important;
    background-repeat: no-repeat !important;
}

/* ========================================
   Waline 评论区优化
   ======================================== */

/* 隐藏 Waline v3 登录按钮 */
.wl-login,
.wl-user,
.wl-panel .wl-login,
.wl-header-item .wl-login-btn {
  display: none !important;
}

/* ========================================
   看板娘立绘
   ======================================== */

#web_bg:after {
    content: "";
    position: fixed;
    right: 15px;
    bottom: 0;
    width: 150px;
    height: 280px;
    background-image: url(/img/character.png);
    background-size: contain;
    background-repeat: no-repeat;
    background-position: right bottom;
    pointer-events: none;
    z-index: 998;
    opacity: 0.8;
}

@media screen and (max-width: 768px) {
    #web_bg:after {
        display: none;
    }
}

/* ========================================
   头图悬浮效果
   ======================================== */

#recent-posts .recent-post-item .post_cover img {
    transition: transform 0.5s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

#recent-posts .recent-post-item .post_cover:hover img {
    transform: scale(1.08) rotate(2deg);
}

/* ========================================
   列表入场动画
   ======================================== */

@keyframes slideUpIn {
    from { opacity: 0; transform: translateY(30px); }
    to { opacity: 1; transform: translateY(0); }
}

#content-inner,
#footer {
    animation: slideUpIn 0.8s ease-out !important;
}

#recent-posts .recent-post-item {
    opacity: 0;
    animation: slideUpIn 0.6s ease-out forwards;
}

#recent-posts .recent-post-item:nth-child(1) { animation-delay: 0.1s; }
#recent-posts .recent-post-item:nth-child(2) { animation-delay: 0.2s; }
#recent-posts .recent-post-item:nth-child(3) { animation-delay: 0.3s; }
#recent-posts .recent-post-item:nth-child(4) { animation-delay: 0.4s; }
#recent-posts .recent-post-item:nth-child(5) { animation-delay: 0.5s; }
#recent-posts .recent-post-item:nth-child(n+6) { animation-delay: 0.6s; }

/* ========================================
   点击特效
   ======================================== */

@keyframes clickHeart {
    0% { opacity: 1; transform: translateY(0) scale(1) rotate(0deg); }
    50% { opacity: 0.8; transform: translateY(-40px) scale(1.2) rotate(-15deg); }
    100% { opacity: 0; transform: translateY(-80px) scale(0.6) rotate(15deg); }
}

@keyframes clickSakura {
    0% { opacity: 1; transform: translateY(0) rotate(0deg) scale(1); }
    40% { opacity: 0.9; transform: translateY(-30px) rotate(90deg) scale(1.1); }
    100% { opacity: 0; transform: translateY(-90px) rotate(270deg) scale(0.4); }
}

.click-effect {
    position: fixed;
    pointer-events: none;
    z-index: 9999;
    animation-fill-mode: forwards;
    font-size: 18px;
    user-select: none;
}

.click-effect.heart {
    animation: clickHeart 1s ease-out forwards;
    color: #c0a0a8;
}

.click-effect.sakura {
    animation: clickSakura 1.2s ease-out forwards;
    color: #d0b8c0;
}

/* ========================================
   右下角按钮
   ======================================== */

#rightside > div > button,
#rightside > div > a {
    background: rgba(255, 255, 255, 0.6) !important;
    backdrop-filter: blur(10px) !important;
    -webkit-backdrop-filter: blur(10px) !important;
    color: #555 !important;
    border: 1px solid rgba(0, 0, 0, 0.06) !important;
    border-radius: 8px !important;
    box-shadow: none !important;
    transition: all 0.3s ease !important;
}

#rightside > div > button:hover,
#rightside > div > a:hover {
    background: rgba(255, 255, 255, 0.8) !important;
    color: #333 !important;
}

[data-theme="dark"] #rightside > div > button,
[data-theme="dark"] #rightside > div > a {
    background: rgba(30, 30, 30, 0.6) !important;
    color: #aaa !important;
    border: 1px solid rgba(255, 255, 255, 0.06) !important;
}

/* ========================================
   APlayer 音乐栏
   ======================================== */

.aplayer.aplayer-fixed {
    background: rgba(255, 255, 255, 0.7) !important;
    backdrop-filter: blur(10px) !important;
    -webkit-backdrop-filter: blur(10px) !important;
    border: 1px solid rgba(0, 0, 0, 0.06) !important;
    border-radius: 8px 8px 0 0 !important;
    box-shadow: none !important;
}

.aplayer.aplayer-fixed .aplayer-body { background: transparent !important; }
.aplayer.aplayer-fixed .aplayer-info { background: transparent !important; border-top: none !important; }
.aplayer.aplayer-fixed .aplayer-miniswitcher { background: rgba(255, 255, 255, 0.7) !important; border-left: 1px solid rgba(0, 0, 0, 0.06) !important; }
.aplayer.aplayer-fixed .aplayer-list { background: rgba(255, 255, 255, 0.75) !important; backdrop-filter: blur(10px) !important; border: 1px solid rgba(0, 0, 0, 0.06) !important; border-bottom: none !important; }

[data-theme="dark"] .aplayer.aplayer-fixed { background: rgba(30, 30, 30, 0.7) !important; border-color: rgba(255,255,255,0.06) !important; }
[data-theme="dark"] .aplayer.aplayer-fixed .aplayer-miniswitcher { background: rgba(30, 30, 30, 0.7) !important; }
[data-theme="dark"] .aplayer.aplayer-fixed .aplayer-list { background: rgba(30, 30, 30, 0.75) !important; }

/* ========================================
   呼吸感间距
   ======================================== */

#content-inner { padding: 20px 24px !important; }
#aside-content { padding: 0 8px !important; }
#recent-posts { padding-right: 16px !important; }
#article-container { padding: 20px 28px !important; }

@media screen and (max-width: 900px) {
    #content-inner { padding: 12px 8px !important; }
    #recent-posts { padding-right: 0 !important; }
    #article-container { padding: 16px 12px !important; }
}

/* ========================================
   终极蓝色消灭 - 覆盖所有 #49b1f5 硬编码
   ======================================== */

/* 链接颜色 */
a, a:hover, .post-title-link, .menu-item-active a,
#article-container a, .tag-cloud a, .category-item a,
.archive-year, .archive-date, .post-meta a,
.site-data a, .aside-list-item a, .card-archives a, .card-categories a, .card-tags a,
.author-info-name a, #card-info-btn,
#nav a, #site-title, #site-subtitle,
.social-icon a, .fas, .fab {
    color: #555 !important;
}

a:hover {
    color: #333 !important;
}

/* 边框类蓝色 */
blockquote, .note.default, .tag-cloud a,
#article-container .tabs .tab-to-top,
.article-sort-item::before,
.related-post-item .title,
.reward-button,
.btn-beautify,
.button--primary,
.tab-active {
    border-color: rgba(0, 0, 0, 0.12) !important;
}

/* 背景类蓝色（按钮、标签、徽章） */
.reward-button,
.btn-beautify.button--primary,
#article-container .tabs .tab-active,
.tag-cloud a:hover,
.pagination .page-number.current,
.nav-links .page-number.current,
button--primary,
.note.primary .note-title,
.blue .tab, .tabs .tab.active {
    background: rgba(0, 0, 0, 0.06) !important;
    color: #555 !important;
}

/* 滚动条 */
*::-webkit-scrollbar-thumb {
    background: rgba(0, 0, 0, 0.15) !important;
}

*::-webkit-scrollbar-thumb:hover {
    background: rgba(0, 0, 0, 0.25) !important;
}

/* HR 分割线 */
hr {
    border-color: rgba(0, 0, 0, 0.08) !important;
}

/* 搜索相关 */
.search-dialog .search-header,
.local-search__highlight,
.algolia-search__highlight {
    color: #555 !important;
    background: rgba(0, 0, 0, 0.04) !important;
}

/* 选中文字 */
::selection {
    background: rgba(0, 0, 0, 0.12) !important;
    color: #fff !important;
}

/* 标签页面 tag 激活色 */
.tag-cloud a:hover,
.category-item:hover .category-count {
    color: #333 !important;
    background: rgba(0, 0, 0, 0.04) !important;
}

/* ===============================
   Butterfly 首页蓝色背景彻底清除
   =============================== */

/* 1. 清除首页顶部大图区域的默认蓝色背景 */
#page-header,
#page-header.full_page {
  background-color: transparent !important;
  filter: none !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}

/* 2. 清除 Butterfly 默认的蓝色/暗色遮罩层 */
#page-header::before,
#page-header.full_page::before,
#page-header:not(.not-top-img)::before {
  background: transparent !important;
  background-color: transparent !important;
  background-image: none !important;
  opacity: 0 !important;
  filter: none !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}

/* 3. 如果主题给首页头图加了 after 遮罩，也一起清掉 */
#page-header::after,
#page-header.full_page::after {
  background: transparent !important;
  background-color: transparent !important;
  background-image: none !important;
  opacity: 0 !important;
}

/* 4. 保证背景壁纸本身清晰，不要模糊 */
#web_bg,
body {
  filter: none !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}

/* 5. 导航栏可以保留浅白磨砂，但不要影响背景壁纸 */
#nav {
  background: rgba(255, 255, 255, 0.55) !important;
  backdrop-filter: blur(10px) !important;
  -webkit-backdrop-filter: blur(10px) !important;
  box-shadow: none !important;
}

/* 6. 首页中间标题文字改深色，避免背景变浅后看不清 */
#site-title,
#site-subtitle,
#page-header #site-title,
#page-header #site-subtitle {
  color: #222 !important;
  text-shadow: none !important;
}

/* 7. 向下滚动箭头改深色 */
#scroll-down .scroll-down-effects {
  color: #222 !important;
  text-shadow: none !important;
}

/* 8. 页脚去掉默认蓝色，改成浅白半透明磨砂 */
#footer {
  background: rgba(255, 255, 255, 0.45) !important;
  backdrop-filter: blur(15px) !important;
  -webkit-backdrop-filter: blur(15px) !important;
  color: #333 !important;
}

#footer::before,
#footer::after {
  background: transparent !important;
  background-color: transparent !important;
  background-image: none !important;
  opacity: 0 !important;
}

#footer,
#footer a {
  color: #333 !important;
  text-shadow: none !important;
}

/* =================================================
   极简二次元风优化 v1
   目标：浅色、低饱和、轻透明、少动效
   ================================================= */

:root {
  --theme-color: #b8a6d9 !important;
  --text-highlight-color: #8f7ab8 !important;
  --light-blue: #b8a6d9 !important;

  --card-bg: rgba(255, 255, 255, 0.72) !important;
  --card-box-shadow: none !important;
  --card-hover-box-shadow: 0 8px 24px rgba(120, 100, 160, 0.10) !important;
}

/* 全局文字：降低锐度，偏清爽 */
body,
.post-body,
h1, h2, h3, h4,
#article-container {
  color: #2f2f35 !important;
  font-family: -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif !important;
}

/* 链接：淡紫，不要全灰 */
a,
.post-title-link,
#article-container a {
  color: #7f6aa3 !important;
  text-decoration: none !important;
}

a:hover,
.post-title-link:hover,
#article-container a:hover {
  color: #5f4a85 !important;
}

/* 首页头部：去掉厚重磨砂，保留轻遮罩 */
#page-header,
#page-header.full_page {
  background-color: transparent !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}

#page-header::before,
#page-header.full_page::before {
  background: rgba(255, 255, 255, 0.16) !important;
  opacity: 1 !important;
}

/* 首页标题：干净一点 */
#site-title,
#site-subtitle,
#page-header #site-title,
#page-header #site-subtitle {
  color: #2f2f35 !important;
  text-shadow: none !important;
}

#site-title {
  font-weight: 600 !important;
  letter-spacing: 0.08em !important;
}

#site-subtitle {
  font-size: 1rem !important;
  opacity: 0.82 !important;
}

/* 导航栏：轻薄 */
#nav,
#nav.nav-fixed,
#nav.show {
  background: rgba(255, 255, 255, 0.58) !important;
  backdrop-filter: blur(8px) !important;
  -webkit-backdrop-filter: blur(8px) !important;
  box-shadow: none !important;
  border-bottom: 1px solid rgba(255, 255, 255, 0.35) !important;
}

#nav a {
  color: #2f2f35 !important;
}

#nav a:hover {
  color: #7f6aa3 !important;
}

/* 卡片：更轻、更软 */
.cardHover,
.card-widget,
.recent-post-item,
.layout > div:first-child:not(.nc),
.layout .pagination > *:not(.space) {
  background: rgba(255, 255, 255, 0.72) !important;
  backdrop-filter: blur(6px) !important;
  -webkit-backdrop-filter: blur(6px) !important;
  border-radius: 16px !important;
  border: 1px solid rgba(255, 255, 255, 0.45) !important;
  box-shadow: none !important;
}

.cardHover:hover,
.recent-post-item:hover,
.card-widget:hover {
  box-shadow: 0 8px 24px rgba(120, 100, 160, 0.10) !important;
  transform: translateY(-2px);
}

/* 文章卡片标题 */
#recent-posts .recent-post-item > .recent-post-info > .article-title {
  color: #2f2f35 !important;
  font-weight: 600 !important;
}

#recent-posts .recent-post-item > .recent-post-info > .content {
  color: #6f6f78 !important;
}

/* 侧边栏头像稍微柔和 */
.avatar-img img,
#aside-content .card-info img {
  border-radius: 18px !important;
}

/* 看板娘：缩小、变淡，不抢主体 */
#web_bg:after {
  right: 24px !important;
  bottom: 0 !important;
  width: 120px !important;
  height: 230px !important;
  opacity: 0.55 !important;
}

/* 去掉过度旋转感，只保留轻微放大 */
#recent-posts .recent-post-item .post_cover:hover img {
  transform: scale(1.03) !important;
}

/* 页脚：极简浅色 */
#footer {
  background: rgba(255, 255, 255, 0.45) !important;
  backdrop-filter: blur(8px) !important;
  -webkit-backdrop-filter: blur(8px) !important;
  color: #666 !important;
  text-shadow: none !important;
  border-top: 1px solid rgba(255, 255, 255, 0.35) !important;
}

#footer a {
  color: #7f6aa3 !important;
}

/* 右下角按钮：淡紫极简 */
#rightside > div > button,
#rightside > div > a {
  background: rgba(255, 255, 255, 0.68) !important;
  color: #7f6aa3 !important;
  border-radius: 12px !important;
  box-shadow: none !important;
  border: 1px solid rgba(184, 166, 217, 0.25) !important;
}

#rightside > div > button:hover,
#rightside > div > a:hover {
  background: rgba(239, 234, 253, 0.9) !important;
  color: #5f4a85 !important;
}

/* 减少动效：极简风不要太跳 */
#content-inner,
#footer,
#recent-posts .recent-post-item {
  animation-duration: 0.45s !important;
}

/* 弱化点击特效：缩小幅度、降透明度 */
.click-effect.heart {
  animation-duration: 0.7s !important;
  font-size: 14px !important;
  opacity: 0.7 !important;
}

.click-effect.sakura {
  animation-duration: 0.8s !important;
  font-size: 14px !important;
  opacity: 0.7 !important;
}

/* Click Effect - Anime Hearts & Sakura */
(function () {
  var hearts = ['❤', '♥', '❣', '♡'];
  var sakuras = ['✿', '❀', '❁', '✾'];
  var isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);

  function createEffect(x, y) {
    var el = document.createElement('span');
    var isSakura = Math.random() > 0.5;
    el.className = 'click-effect ' + (isSakura ? 'sakura' : 'heart');
    el.textContent = isSakura
      ? sakuras[Math.floor(Math.random() * sakuras.length)]
      : hearts[Math.floor(Math.random() * hearts.length)];
    el.style.left = x + 'px';
    el.style.top = y + 'px';
    el.style.fontSize = (14 + Math.random() * 12) + 'px';
    document.body.appendChild(el);
    el.addEventListener('animationend', function () {
      el.remove();
    });
  }

  document.addEventListener('click', function (e) {
    if (isMobile) return;
    var count = 1 + Math.floor(Math.random() * 3);
    for (var i = 0; i < count; i++) {
      (function (delay) {
        setTimeout(function () {
          createEffect(
            e.clientX + (Math.random() - 0.5) * 30,
            e.clientY + (Math.random() - 0.5) * 20
          );
        }, delay * 80);
      })(i);
    }
  });
})();

